function stringScrumble(str1,str2){var res='';if(str1.length!=str2.length){return!1}else{for(i=0;i<str1.length;i++){res=res.concat(str1.charAt(i)).concat(str2.charAt(i))}}
return res}
function stringDecrumble(str,mode){if(str.length%2!=0)
return!1;var res='';if(mode===undefined)
mode=1;switch(mode){case 1:for(i=0;i<str.length;i+=2){res=res.concat(str.charAt(i))}
break;case 2:for(i=1;i<str.length;i+=2){res=res.concat(str.charAt(i))}
break}
return res}
function displayImageFromInput(input,img,params={}){return new Promise(function(resolve,reject){if(params.checkElements===undefined)
params.checkElements=!0;if(params.checkElements){if(!isElement(input))
input=document.querySelector(input);if(!isElement(img))
img=document.querySelector(img);if(!isElement(input)||!isElement(img)||img.nodeName!=='IMG'||input.nodeName!=='INPUT'){console.log('Elements not found or invalid!');resolve(!1);return}}
let files=input.files;if(files.length===0){console.log('No files uploaded, cannot generate preview!');resolve(!1);return}
let file=files[0];var imageType=file.type;var blob=null;file.arrayBuffer().then(function(resolve,reject){blob=new Blob([resolve],{type:imageType});let urlCreator=window.URL||window.webkitURL;img.src=urlCreator.createObjectURL(blob)})})}
function bindImagePreview(input,img,params={}){var callback=(params.callback!==undefined)?params.callback:function(){};var bindClick=(params.bindClick)?!0:!1;if(bindClick)
img.onclick=function(){input.click()};input.onchange=function(){displayImageFromInput(input,img,{'checkElements':!1});callback()}}